import React from 'react';

// Simple Bar Chart Component (SVG-based, no external dependencies)
export function BarChart({ data, title, xLabel, yLabel, maxHeight = 200 }) {
  if (!data || data.length === 0) {
    return <div className="text-gray-400">No data to display</div>;
  }

  const maxValue = Math.max(...data.map(d => d.value || 0), 1);
  const chartWidth = Math.max(400, data.length * 50);
  const barWidth = Math.min(40, chartWidth / data.length - 10);
  const padding = 40;

  return (
    <div className="bg-white p-4 rounded shadow">
      {title && <h3 className="font-semibold mb-4">{title}</h3>}
      <svg width={chartWidth} height={maxHeight + padding * 2} className="border rounded">
        {/* Y-axis */}
        <line x1={padding} y1={padding} x2={padding} y2={maxHeight + padding} stroke="#ccc" strokeWidth="1" />
        {/* X-axis */}
        <line x1={padding} y1={maxHeight + padding} x2={chartWidth - padding} y2={maxHeight + padding} stroke="#ccc" strokeWidth="1" />
        
        {/* Grid lines and Y-axis labels */}
        {[0, 0.25, 0.5, 0.75, 1].map((fraction, i) => {
          const y = maxHeight + padding - fraction * maxHeight;
          const value = Math.round(maxValue * fraction);
          return (
            <g key={`grid-${i}`}>
              <line x1={padding - 5} y1={y} x2={padding} y2={y} stroke="#ccc" strokeWidth="1" />
              <text x={padding - 30} y={y + 4} fontSize="10" fill="#666">
                {value}
              </text>
            </g>
          );
        })}
        
        {/* Y-axis label */}
        {yLabel && (
          <text x="10" y="20" fontSize="12" fill="#333" fontWeight="bold">
            {yLabel}
          </text>
        )}
        
        {/* Bars */}
        {data.map((item, idx) => {
          const barHeight = (item.value / maxValue) * maxHeight;
          const x = padding + idx * (barWidth + 10) + 5;
          const y = maxHeight + padding - barHeight;
          const color = item.color || '#3b82f6';
          
          return (
            <g key={`bar-${idx}`}>
              <rect x={x} y={y} width={barWidth} height={barHeight} fill={color} />
              <title>{`${item.label}: ${item.value}`}</title>
              <text
                x={x + barWidth / 2}
                y={maxHeight + padding + 20}
                fontSize="10"
                textAnchor="middle"
                fill="#666"
              >
                {item.label}
              </text>
            </g>
          );
        })}
        
        {/* X-axis label */}
        {xLabel && (
          <text
            x={chartWidth / 2}
            y={maxHeight + padding + 40}
            fontSize="12"
            fill="#333"
            fontWeight="bold"
            textAnchor="middle"
          >
            {xLabel}
          </text>
        )}
      </svg>
    </div>
  );
}

// Simple Line Chart Component (SVG-based)
export function LineChart({ data, title, xLabel, yLabel, maxHeight = 200 }) {
  if (!data || data.length === 0) {
    return <div className="text-gray-400">No data to display</div>;
  }

  const maxValue = Math.max(...data.map(d => d.value || 0), 1);
  const chartWidth = Math.max(400, data.length * 50);
  const padding = 40;
  const pointRadius = 4;

  // Calculate points
  const points = data.map((item, idx) => {
    const x = padding + (idx / Math.max(data.length - 1, 1)) * (chartWidth - 2 * padding);
    const y = maxHeight + padding - (item.value / maxValue) * maxHeight;
    return { x, y, ...item };
  });

  // Create path for line
  const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');

  return (
    <div className="bg-white p-4 rounded shadow">
      {title && <h3 className="font-semibold mb-4">{title}</h3>}
      <svg width={chartWidth} height={maxHeight + padding * 2} className="border rounded">
        {/* Y-axis */}
        <line x1={padding} y1={padding} x2={padding} y2={maxHeight + padding} stroke="#ccc" strokeWidth="1" />
        {/* X-axis */}
        <line x1={padding} y1={maxHeight + padding} x2={chartWidth - padding} y2={maxHeight + padding} stroke="#ccc" strokeWidth="1" />
        
        {/* Grid lines */}
        {[0, 0.25, 0.5, 0.75, 1].map((fraction, i) => {
          const y = maxHeight + padding - fraction * maxHeight;
          const value = Math.round(maxValue * fraction);
          return (
            <g key={`grid-${i}`}>
              <line x1={padding - 5} y1={y} x2={padding} y2={y} stroke="#ccc" strokeWidth="1" />
              <text x={padding - 30} y={y + 4} fontSize="10" fill="#666">
                {value}
              </text>
            </g>
          );
        })}
        
        {/* Y-axis label */}
        {yLabel && (
          <text x="10" y="20" fontSize="12" fill="#333" fontWeight="bold">
            {yLabel}
          </text>
        )}
        
        {/* Line */}
        <path d={pathD} stroke="#3b82f6" strokeWidth="2" fill="none" />
        
        {/* Points */}
        {points.map((point, idx) => (
          <g key={`point-${idx}`}>
            <circle cx={point.x} cy={point.y} r={pointRadius} fill="#3b82f6" />
            <title>{`${point.label}: ${point.value}`}</title>
            <text
              x={point.x}
              y={maxHeight + padding + 20}
              fontSize="10"
              textAnchor="middle"
              fill="#666"
            >
              {point.label}
            </text>
          </g>
        ))}
        
        {/* X-axis label */}
        {xLabel && (
          <text
            x={chartWidth / 2}
            y={maxHeight + padding + 40}
            fontSize="12"
            fill="#333"
            fontWeight="bold"
            textAnchor="middle"
          >
            {xLabel}
          </text>
        )}
      </svg>
    </div>
  );
}

// Pie/Donut Chart Component
export function PieChart({ data, title, maxHeight = 250 }) {
  if (!data || data.length === 0) {
    return <div className="text-gray-400">No data to display</div>;
  }

  const total = data.reduce((sum, item) => sum + item.value, 0);
  const radius = 80;
  const centerX = maxHeight / 2 + 20;
  const centerY = maxHeight / 2;

  const colors = ['#3b82f6', '#ef4444', '#10b981', '#f59e0b', '#8b5cf6', '#ec4899'];

  let currentAngle = -Math.PI / 2;
  const slices = data.map((item, idx) => {
    const sliceAngle = (item.value / total) * 2 * Math.PI;
    const startAngle = currentAngle;
    const endAngle = currentAngle + sliceAngle;

    const x1 = centerX + radius * Math.cos(startAngle);
    const y1 = centerY + radius * Math.sin(startAngle);
    const x2 = centerX + radius * Math.cos(endAngle);
    const y2 = centerY + radius * Math.sin(endAngle);

    const largeArc = sliceAngle > Math.PI ? 1 : 0;
    const pathD = `M ${centerX} ${centerY} L ${x1} ${y1} A ${radius} ${radius} 0 ${largeArc} 1 ${x2} ${y2} Z`;

    const labelAngle = startAngle + sliceAngle / 2;
    const labelRadius = radius * 0.65;
    const labelX = centerX + labelRadius * Math.cos(labelAngle);
    const labelY = centerY + labelRadius * Math.sin(labelAngle);
    const percentage = ((item.value / total) * 100).toFixed(1);

    currentAngle = endAngle;

    return { pathD, labelX, labelY, percentage, color: colors[idx % colors.length], ...item };
  });

  return (
    <div className="bg-white p-4 rounded shadow">
      {title && <h3 className="font-semibold mb-4">{title}</h3>}
      <div className="flex">
        <svg width={maxHeight + 40} height={maxHeight + 40} viewBox={`0 0 ${maxHeight + 40} ${maxHeight + 40}`}>
          {slices.map((slice, idx) => (
            <g key={`slice-${idx}`}>
              <path d={slice.pathD} fill={slice.color} opacity="0.8" />
              <title>{`${slice.label}: ${slice.value} (${slice.percentage}%)`}</title>
              <text x={slice.labelX} y={slice.labelY} fontSize="12" fontWeight="bold" fill="white" textAnchor="middle">
                {slice.percentage}%
              </text>
            </g>
          ))}
        </svg>
        <div className="ml-4 flex flex-col justify-center text-sm">
          {slices.map((slice, idx) => (
            <div key={`legend-${idx}`} className="flex items-center gap-2 mb-2">
              <div className="w-3 h-3 rounded-full" style={{ backgroundColor: slice.color }}></div>
              <span>{slice.label}: {slice.value}</span>
            </div>
          ))}
        </div>
      </div>
    </div>
  );
}

// Time Series Chart with multiple metrics
export function TimeSeriesChart({ data, title, maxHeight = 250 }) {
  if (!data || data.length === 0) {
    return <div className="text-gray-400">No data to display</div>;
  }

  const chartWidth = Math.max(400, data.length * 40);
  const padding = 40;
  const colors = ['#3b82f6', '#ef4444', '#10b981', '#f59e0b'];

  // Get all metric keys
  const metricKeys = Object.keys(data[0]).filter(k => k !== 'timestamp' && k !== 'label');
  const allValues = data.flatMap(d => metricKeys.map(k => d[k]));
  const maxValue = Math.max(...allValues, 1);

  return (
    <div className="bg-white p-4 rounded shadow">
      {title && <h3 className="font-semibold mb-4">{title}</h3>}
      <svg width={chartWidth} height={maxHeight + padding * 2} className="border rounded">
        {/* Axes */}
        <line x1={padding} y1={padding} x2={padding} y2={maxHeight + padding} stroke="#ccc" strokeWidth="1" />
        <line x1={padding} y1={maxHeight + padding} x2={chartWidth - padding} y2={maxHeight + padding} stroke="#ccc" strokeWidth="1" />

        {/* Grid lines and Y-axis labels */}
        {[0, 0.25, 0.5, 0.75, 1].map((fraction, i) => {
          const y = maxHeight + padding - fraction * maxHeight;
          const value = Math.round(maxValue * fraction);
          return (
            <g key={`grid-${i}`}>
              <line x1={padding - 5} y1={y} x2={padding} y2={y} stroke="#ccc" strokeWidth="1" />
              <text x={padding - 30} y={y + 4} fontSize="10" fill="#666">
                {value}
              </text>
            </g>
          );
        })}

        {/* Lines for each metric */}
        {metricKeys.map((metric, metricIdx) => {
          const points = data.map((item, dataIdx) => {
            const x = padding + (dataIdx / Math.max(data.length - 1, 1)) * (chartWidth - 2 * padding);
            const y = maxHeight + padding - (item[metric] / maxValue) * maxHeight;
            return { x, y };
          });

          const pathD = points.map((p, i) => `${i === 0 ? 'M' : 'L'} ${p.x} ${p.y}`).join(' ');
          return (
            <path key={`line-${metricIdx}`} d={pathD} stroke={colors[metricIdx % colors.length]} strokeWidth="2" fill="none" />
          );
        })}

        {/* Data points */}
        {metricKeys.map((metric, metricIdx) => (
          data.map((item, dataIdx) => {
            const x = padding + (dataIdx / Math.max(data.length - 1, 1)) * (chartWidth - 2 * padding);
            const y = maxHeight + padding - (item[metric] / maxValue) * maxHeight;
            return (
              <circle key={`point-${metricIdx}-${dataIdx}`} cx={x} cy={y} r="3" fill={colors[metricIdx % colors.length]} />
            );
          })
        ))}

        {/* X-axis labels */}
        {data.map((item, idx) => {
          if (idx % Math.ceil(data.length / 5) === 0) {
            const x = padding + (idx / Math.max(data.length - 1, 1)) * (chartWidth - 2 * padding);
            return (
              <text key={`label-${idx}`} x={x} y={maxHeight + padding + 20} fontSize="10" textAnchor="middle" fill="#666">
                {item.label || item.timestamp}
              </text>
            );
          }
          return null;
        })}
      </svg>

      {/* Legend */}
      <div className="mt-4 flex gap-4 flex-wrap">
        {metricKeys.map((metric, idx) => (
          <div key={`legend-${idx}`} className="flex items-center gap-2">
            <div className="w-3 h-3 rounded" style={{ backgroundColor: colors[idx % colors.length] }}></div>
            <span className="text-sm">{metric}</span>
          </div>
        ))}
      </div>
    </div>
  );
}

export default { BarChart, LineChart, PieChart, TimeSeriesChart };
